import java.util.*;
import java.util.function.*;

public class Main {
    public static void main(String[] args) {
        // Lambda with custom functional interface
        Calculator add = (a, b) -> a + b;
        Calculator multiply = (a, b) -> a * b;

        System.out.println("Add: " + operate(5, 3, add));
        System.out.println("Multiply: " + operate(5, 3, multiply));

        // Using built-in functional interfaces
        List<String> names = Arrays.asList("Alice", "Bob", "Charlie");

        // Consumer
        names.forEach(name -> System.out.println("Hello, " + name));

        // Predicate
        names.removeIf(name -> name.startsWith("A"));
        System.out.println("After filter: " + names);

        // Supplier
        Supplier<Double> randomSupplier = () -> Math.random();
        System.out.println("Random: " + randomSupplier.get());
    }

    static int operate(int a, int b, Calculator calc) {
        return calc.calculate(a, b);
    }
}

@FunctionalInterface
interface Calculator {
    int calculate(int a, int b);
}
